var maximumLength = function(nums, k) {
    const n = nums.length;
    const dp = Array.from({length: n}, () => new Array(k + 1).fill(1));
    let ans = 1;
    for (let i = 0; i < n; i++) {
        for (let p = 0; p < i; p++) {
            for (let j = 0; j <= k; j++) {
                if (nums[p] === nums[i]) {
                    if (dp[p][j] + 1 > dp[i][j]) dp[i][j] = dp[p][j] + 1;
                } else if (j > 0) {
                    if (dp[p][j-1] + 1 > dp[i][j]) dp[i][j] = dp[p][j-1] + 1;
                }
            }
        }
        for (let j = 0; j <= k; j++) if (dp[i][j] > ans) ans = dp[i][j];
    }
    return ans;
};
